#include <stdlib.h>
#include <string.h>
#include <math.h>
#define MAX 1000001
#define MOD 1000000007

int prime[MAX];
int dp[MAX];

void sieve() {
    for (int i = 2; i * i <= MAX; i++) {
        if (!prime[i]) {
            for (int j = i * i; j <= MAX; j += i) {
                prime[j] = 1;
            }
        }
    }
}

int countPrimeFactors(int n) {
    int count = 0;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            count++;
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        count++;
    }
    return count;
}

